from flask import Flask, render_template, request, redirect, url_for
from jinja2 import Template
from models import Opportunity, OpportunityForm

app = Flask(__name__)

@app.route('/opportunities/<int:opp_id>/edit', methods=['GET', 'POST'])
def edit_opportunity(opp_id):
    opportunity = Opportunity.query.get(opp_id)
    form = OpportunityForm(obj=opportunity)

    if request.method == 'POST':
        if form.validate_on_submit():
            form.populate_obj(opportunity)
            opportunity.save()  # Assuming there's a save method to update the database
            return redirect(url_for('opportunity_detail', opp_id=opp_id))

    description_field = form.description.data  # Assuming 'description' is a field in the form

    return render_template('edit_opportunity.html',
        form=form, description_field=description_field)
